#!/bin/bash

# Helper script to deploy a contract with ABI using grpcurl
# Uses plain hex strings (updated for new proto definition)

# Colors for output
GREEN='\033[0;32m'
BLUE='\033[0;34m'
RED='\033[0;31m'
NC='\033[0m' # No Color

echo -e "${BLUE}=== SmartContract Deployment Helper ===${NC}\n"

# Default values (you can edit these)
CALLER_HEX="0x1234567890123456789012345678901234567890"
BYTECODE=""
ABI='[{"inputs":[],"name":"message","outputs":[{"internalType":"string","name":"","type":"string"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"string","name":"newMessage","type":"string"}],"name":"setMessage","outputs":[],"stateMutability":"nonpayable","type":"function"}]'
VALUE_HEX="0x00"
GAS_LIMIT=3000000

echo -e "${GREEN}Using Hex values directly...${NC}"
echo "Caller: $CALLER_HEX"
echo "Value: $VALUE_HEX"
echo ""

# Escape the ABI JSON for shell
ABI_ESCAPED=$(echo "$ABI" | sed 's/"/\\"/g')

echo -e "${BLUE}Sending deployment request...${NC}\n"

# Make the grpcurl call and save response
RESPONSE=$(grpcurl -plaintext \
  -d "{
    \"caller\": \"$CALLER_HEX\",
    \"bytecode\": \"$BYTECODE\",
    \"abi\": \"$ABI_ESCAPED\",
    \"gas_limit\": $GAS_LIMIT,
    \"value\": \"$VALUE_HEX\"
  }" \
  localhost:15055 \
  smartcontract.SmartContractService/DeployContract 2>&1)

# Display raw response
echo "$RESPONSE"

# Extract and decode contract address if successful
if echo "$RESPONSE" | grep -q '"success": true'; then
    echo -e "\n${GREEN}=== Deployment Successful ===${NC}"
    
    # Extract contract address (it is now hex string)
    CONTRACT_ADDR=$(echo "$RESPONSE" | grep -o '"contractAddress": "[^"]*"' | cut -d'"' -f4)
    
    if [ -n "$CONTRACT_ADDR" ]; then
        echo -e "${GREEN}Contract Address:${NC} $CONTRACT_ADDR"
        
        # Extract gas used
        GAS_USED=$(echo "$RESPONSE" | grep -o '"gasUsed": "[^"]*"' | cut -d'"' -f4)
        echo -e "${GREEN}Gas Used:${NC} $GAS_USED"
    fi
else
    echo -e "\n${RED}Deployment failed!${NC}"
fi

echo -e "\n${GREEN}Done!${NC}"
